// import * as React from "react"
import React, {useState} from "react";
import { Link, graphql } from "gatsby"
import {useLocation} from "@reach/router";
import Layout from "../components/layout"
import Seo from "../components/seo"
import PostList from "../components/postList";

export default ({data}) => {
    const location = useLocation();
    const queryParams = new URLSearchParams(location.search);
    const selectedTag = queryParams.get("tag");

    const [filteredPosts, setFilteredPosts] = useState(data.allMarkdownRemark.edges)

  // // selectedTag가 있을 경우에만 필터링
  //   const filteredPosts = selectedTag
  //   ? data.allMarkdownRemark.edges.filter(
  //       ({ node }) => node.frontmatter.tag === selectedTag
  //     )
  //   : data.allMarkdownRemark.edges

  //태그를 클릭 할 때마다 setFilteredPosts가 동작해서 현재 선택된 태그를 변경하고
  //변경된 태그에 따라 게시물 다르게 보여주기
  //

    return(
        <Layout>
        <h1>Hi from the second page</h1>
        <p>Welcome to page 2</p>
        <br/><br/><br/>
        <h1>선택된 태그 : {selectedTag}</h1>
        <PostList posts={filteredPosts}/>
      </Layout>
    );
};

export const Head = () => <Seo title="Page two" />

export const query = graphql`
  query {
    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      totalCount
      edges {
        node {
          id
          frontmatter {
            title
            date(formatString: "MMMM DD, YYYY")
            tag
            series
          }
          fields{
            slug
          }
          excerpt(truncate: true, pruneLength: 223)          
        }
      }
    }
  }
`